#include<bits/stdc++.h>
using namespace std;
const long long mod=1e9+9;
long long n,k,ans[2010],a[2010],b[2010],r[2010],dp[2010][2010],f[2010],jc[2010],ny[2010];
long long C(long long n,long long m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    scanf("%lld%lld",&n,&k);
    if((n+k)%2==1)
    {
        printf("0");
        return 0;
    }
    k=(n+k)/2;
    jc[0]=ny[0]=1;
    for(long long i=1;i<=n;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[n]=fastpow(jc[n],mod-2);
    for(long long i=n-1;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    sort(a+1,a+1+n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    sort(b+1,b+1+n);
    long long j=0;
    for(long long i=1;i<=n;i++)
    {
        while(j<n&&b[j+1]<a[i])
        {
            j++;
        }
        r[i]=j;
    }
    dp[0][0]=1;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=0;j<=i;j++)
        {
            dp[i][j]=(dp[i-1][j]+(j==0?0ll:1ll*(r[i]-j+1)*dp[i-1][j-1]%mod))%mod;
        }
    }
    for(long long i=0;i<=n;i++)
    {
        f[i]=dp[n][i]*jc[n-i]%mod;
    }
    for(long long i=n;i>=k;i--)
    {
        ans[i]=f[i];
        for(long long j=i+1;j<=n;j++)
        {
            ans[i]=((ans[i]-ans[j]*C(j,i)%mod)%mod+mod)%mod;
        }
    }
    printf("%lld",ans[k]);
    return 0;
}
